record.field:
{
    "type": "object",
    "properties": {
        "period": {"type": "string", "enum": ["today", "week", "month", "year", "all"], "description": "Periodo (padrao: month)"},
        "state": {"type": "string", "enum": ["draft", "sale", "done", "cancel", "all"], "description": "Estado do pedido (padrao: all exceto cancelados)"},
        "salesperson": {"type": "string", "description": "Filtrar por nome do vendedor"}
    }
}

{
    "type": "object",
    "properties": {
        "partner": {"type": "string", "description": "Nome ou ID do cliente"},
        "lines": {"type": "array", "items": {"type": "object", "properties": {"product": {"type": "string", "description": "Nome ou ID do produto"}, "qty": {"type": "number", "description": "Quantidade"}, "price": {"type": "number", "description": "Preco unitario (opcional, usa preco do produto)"}}}, "description": "Linhas do pedido"},
        "note": {"type": "string", "description": "Nota interna (opcional)"}
    },
    "required": ["partner", "lines"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Nome da oportunidade"},
        "partner": {"type": "string", "description": "Nome ou email do contato"},
        "expected_revenue": {"type": "number", "description": "Receita esperada"},
        "description": {"type": "string", "description": "Descricao/notas"},
        "type": {"type": "string", "enum": ["lead", "opportunity"], "description": "Tipo (padrao: opportunity)"}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "project": {"type": "string", "description": "Nome do projeto (filtra)"},
        "user": {"type": "string", "description": "Nome do responsavel (filtra)"},
        "period": {"type": "string", "enum": ["today", "week", "month", "year"], "description": "Periodo para horas (padrao: month)"}
    }
}

{
    "type": "object",
    "properties": {
        "task": {"type": "string", "description": "Nome ou ID da tarefa"},
        "hours": {"type": "number", "description": "Horas trabalhadas (ex: 1.5 = 1h30)"},
        "description": {"type": "string", "description": "Descricao do trabalho"},
        "date": {"type": "string", "description": "Data (YYYY-MM-DD, padrao: hoje)"}
    },
    "required": ["task", "hours", "description"]
}

{
    "type": "object",
    "properties": {
        "project": {"type": "string", "description": "Nome ou ID do projeto"},
        "name": {"type": "string", "description": "Nome da tarefa"},
        "description": {"type": "string", "description": "Descricao"},
        "assignee": {"type": "string", "description": "Nome do responsavel"},
        "deadline": {"type": "string", "description": "Prazo (YYYY-MM-DD)"},
        "priority": {"type": "string", "enum": ["0", "1"], "description": "0=normal, 1=urgente"}
    },
    "required": ["project", "name"]
}

{
    "type": "object",
    "properties": {
        "query": {"type": "string", "description": "Nome, email, telefone ou CNPJ/CPF a buscar"},
        "is_company": {"type": "boolean", "description": "Filtrar apenas empresas"},
        "customer": {"type": "boolean", "description": "Filtrar apenas clientes (com vendas)"},
        "supplier": {"type": "boolean", "description": "Filtrar apenas fornecedores"}
    },
    "required": ["query"]
}

{
    "type": "object",
    "properties": {
        "product": {"type": "string", "description": "Nome do produto (busca parcial)"},
        "low_stock": {"type": "boolean", "description": "Apenas produtos com estoque abaixo do minimo"},
        "warehouse": {"type": "string", "description": "Nome do armazem"},
        "limit": {"type": "integer", "description": "Limite de resultados (padrao: 20)"}
    }
}

{
    "type": "object",
    "properties": {
        "product": {"type": "string", "description": "Nome do produto"},
        "picking_type": {"type": "string", "enum": ["incoming", "outgoing", "internal"], "description": "Tipo: incoming=entrada, outgoing=saida, internal=transferencia"},
        "period": {"type": "string", "enum": ["today", "week", "month"], "description": "Periodo (padrao: week)"},
        "limit": {"type": "integer", "description": "Limite (padrao: 20)"}
    }
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Titulo do evento"},
        "start": {"type": "string", "description": "Data/hora inicio (YYYY-MM-DD HH:MM)"},
        "stop": {"type": "string", "description": "Data/hora fim (YYYY-MM-DD HH:MM)"},
        "attendees": {"type": "array", "items": {"type": "string"}, "description": "Nomes ou emails dos participantes"},
        "description": {"type": "string"}
    },
    "required": ["name", "start", "stop"]
}

{
    "type": "object",
    "properties": {
        "partner": {"type": "string", "description": "Nome ou ID do cliente/fornecedor"},
        "type": {"type": "string", "enum": ["out_invoice", "in_invoice", "out_refund", "in_refund"], "description": "Tipo (padrao: out_invoice)"},
        "lines": {"type": "array", "items": {"type": "object", "properties": {"product": {"type": "string"}, "qty": {"type": "number"}, "price": {"type": "number"}, "description": {"type": "string"}}}, "description": "Linhas da fatura"},
        "ref": {"type": "string", "description": "Referencia externa"}
    },
    "required": ["partner", "lines"]
}

{
    "type": "object",
    "properties": {
        "invoice": {"type": "string", "description": "Numero ou ID da fatura"},
        "amount": {"type": "number", "description": "Valor (padrao: total da fatura)"},
        "journal": {"type": "string", "description": "Diario de pagamento (ex: Banco, Caixa)"}
    },
    "required": ["invoice"]
}

{
    "type": "object",
    "properties": {
        "partner": {"type": "string", "description": "Nome ou ID do fornecedor"},
        "lines": {"type": "array", "items": {"type": "object", "properties": {"product": {"type": "string"}, "qty": {"type": "number"}, "price": {"type": "number"}}}, "description": "Linhas do pedido"}
    },
    "required": ["partner", "lines"]
}

{
    "type": "object",
    "properties": {
        "query": {"type": "string", "description": "Nome, referencia ou codigo de barras"},
        "category": {"type": "string", "description": "Filtrar por categoria"},
        "type": {"type": "string", "enum": ["consu", "service", "product"], "description": "Tipo: consu=consumivel, service=servico, product=estocavel"},
        "limit": {"type": "integer", "description": "Limite (padrao: 10)"}
    },
    "required": ["query"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Nome do produto"},
        "type": {"type": "string", "enum": ["consu", "service", "product"], "description": "Tipo (padrao: consu)"},
        "list_price": {"type": "number", "description": "Preco de venda"},
        "standard_price": {"type": "number", "description": "Custo"},
        "default_code": {"type": "string", "description": "Referencia interna"},
        "barcode": {"type": "string", "description": "Codigo de barras"},
        "description": {"type": "string"}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Descricao da despesa"},
        "amount": {"type": "number", "description": "Valor total"},
        "date": {"type": "string", "description": "Data (YYYY-MM-DD, padrao: hoje)"},
        "product": {"type": "string", "description": "Categoria/produto da despesa (ex: Refeicao, Transporte)"}
    },
    "required": ["name", "amount"]
}

{
    "type": "object",
    "properties": {
        "to": {"type": "array", "items": {"type": "string"}, "description": "Nomes ou emails dos destinatarios"},
        "body": {"type": "string", "description": "Corpo da mensagem"},
        "subject": {"type": "string", "description": "Assunto (opcional)"}
    },
    "required": ["to", "body"]
}

{
    "type": "object",
    "properties": {
        "period": {"type": "string", "enum": ["week", "month", "quarter", "year"], "description": "Periodo (padrao: month)"},
        "limit": {"type": "integer", "description": "Top N produtos (padrao: 10)"},
        "order_by": {"type": "string", "enum": ["qty", "revenue"], "description": "Ordenar por quantidade ou receita (padrao: revenue)"}
    }
}

{
    "type": "object",
    "properties": {
        "upcoming": {"type": "boolean", "description": "Apenas eventos futuros (padrao: true)"},
        "name": {"type": "string", "description": "Filtrar por nome do evento"}
    }
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Filtrar por nome do modulo"},
        "state": {"type": "string", "enum": ["installed", "uninstalled", "to upgrade"], "description": "Estado (padrao: installed)"},
        "apps_only": {"type": "boolean", "description": "Apenas aplicacoes (padrao: true)"}
    }
}

{
    "type": "object",
    "properties": {
        "user": {"type": "string", "description": "Filtrar por nome do usuario"},
        "active_today": {"type": "boolean", "description": "Apenas usuarios que acessaram hoje"}
    }
}
